var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>제목: 소문의 메이드를 찾습니다.</color>","JPN":"<color=#ffd34c>タイトル：噂のメイドを探しています。</color>","ENG":"<color=#ffd34c>Title: Looking for the Rumored Maids.</color>","TWN":"<color=#ffd34c>標題：尋找傳說中的女僕。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>내용: 최근 자신들과 같은 메이드 옷의 사람을 찾고</color>\\n<color=#ffd34c>있는 2인조에게 전합니다.</color>","JPN":"<color=#ffd34c>本文：最近噂の私たちと同じメイド服の人物を</color>\\n<color=#ffd34c>探している、2人組のメイドにお伝えします。</color>","ENG":"<color=#ffd34c>Content: I'm writing this to the duo that has been asking around</color>\\n<color=#ffd34c>for a person in the same maid outfit as them.</color>","TWN":"<color=#ffd34c>內容：致正在尋找身穿與自己同樣女僕裝</color>\\n<color=#ffd34c>的2人組。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>저는 여러분이 찾는 사람입니다.</color>\\n<color=#ffd34c>내일 항만에서 기다리고 있겠습니다.</color>","JPN":"<color=#ffd34c>私はあなた方が探している者です。</color>\\n<color=#ffd34c>明日、港湾でお待ちしております。</color>","ENG":"<color=#ffd34c>I'm the one you're looking for.</color>\\n<color=#ffd34c>I'll be waiting for you at the harbor tomorrow.</color>","TWN":"<color=#ffd34c>我就是各位要找的人。</color>\\n<color=#ffd34c>我明天會在港口恭候2位。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"정말 여기서 내려 주면 돼요? 이 주변은 전부 기간 시설뿐인데?","JPN":"本当にここに降ろせばいいの？　この辺は機関施設しかないよ？","ENG":"You sure this is where you want us to drop you off? There are only factories and warehouses around here.","TWN":"真的要停在這裡嗎？這附近只有公家機關而已啊？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"괜찮습니다. 평소에도 산책을 자주 하는 편이었던 것 같으니까요.","JPN":"大丈夫です。普段も一人で色んな所を散歩していた気がするので。","ENG":"Yes, it's fine. It seems I've been accustomed to going on long walks.","TWN":"沒關係，我以前應該也是經常散步的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하핫! 그래도 기왕이면 꼬마 메이드도 같이 데려오지 그랬어!","JPN":"ガハハハッ！　でもよ、せっかくならあのチビメイドちゃんも連れてくればいいのにな！","ENG":"Hah hah! You should have brought the little maid kid along though.","TWN":"哈哈！妳怎麼不帶小女僕一起過來呢！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"메이드 누님이 혼자 휴가 냈다는 말을 듣고 실망한 것 같던데......","JPN":"メイドのお姉ちゃんが一人で休みになったと聞いて落ち込んでいたぞ。","ENG":"She seemed pretty disappointed that you went off on vacation by yourself...","TWN":"她聽到妳自己去休假，好像還蠻失望的……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":" 크억!","JPN":"ガハッ！","ENG":" Ack!","TWN":" 咳呃！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L14_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"야, 이 눈치 없는 자식아. 덩치는 산 만해서 주둥이는 왜 그렇게 깃털 같아?","JPN":"ちょっとあんた、空気読みなさいよ！　でっかい図体しといて、どうして口はそんなに軽いのかしら！","ENG":"You clueless idiot! Is your mouth as big as your dumb sack of muscles?","TWN":"喂，你這個不會看場合的傢伙，你不說話沒人把你當啞巴！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......휴가, 잘 쉬다 와. 아줌마.","JPN":"……お休み、ゆっくりしてね。おばさん。","ENG":"... Have fun, Veronica.","TWN":"……趁這個假期好好休息一下吧，大嬸。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 편히 쉬고 오겠습니다. 걱정해 주셔서 감사합니다.","JPN":"はい、ゆっくりさせていただきます。ご心配ありがとうございます。","ENG":"Thank you for your well wishes.","TWN":"嗯，我會好好休息的，謝謝妳。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 이건 아침에 만든 머핀입니다. 돌아가서 모네와 같이 드셔 주세요.","JPN":"そしてこれは今朝作ったマフィンです。お戻りになりましたら、モネと一緒に召し上がってください。","ENG":"Here are some muffins that I made this morning. Please share them with Mone once you get back.","TWN":"還有這是我早上做的瑪芬，回去跟莫妮一起吃吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이게...... 머핀...... 푹신푹신......","JPN":"これが……マフィン……ふわっふわの……","ENG":"These are... muffins... So fluffy...","TWN":"這個……瑪芬……鬆鬆軟軟……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"응. 해치울게. 같이.","JPN":"うん。やっつける。一緒に。","ENG":"Okay... We'll eat... together.","TWN":"嗯，一起吃。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"혹시나 장난일지도 모른다고 걱정했지만...... 정말 기다리고 계셨군요.","JPN":"本当に来るのか半信半疑でしたが……来てくださったのですね。","ENG":"I was worried this may have been a prank... But you were really waiting for me.","TWN":"我原本擔心是有人在惡作劇……沒想到真的有人在等我。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그야 당연하지. 메이드는 손님을 기다리는 일에 익숙해야 하니까.","JPN":"当たり前でしょ。メイドはお客様を待つことにも慣れているからね。","ENG":"Of course. Maids must be accustomed to waiting for their guests.","TWN":"當然了，作為女僕應該隨時準備迎接客人。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇군요. 가르침을 받았습니다.","JPN":"そうでしたか。勉強になります。","ENG":"I see. Thank you for that lesson.","TWN":"原來如此，我受教了。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는 메이드, 베로니카라고 합니다.","JPN":"私はメイド、ベロニカと申します。","ENG":"I'm Veronica, a maid.","TWN":"我是女僕，貝洛妮卡。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 그 외에는...... 아무것도 기억나지 않아요.","JPN":"ですがそれ以外のことは……何も思い出せません。","ENG":"But that's all I seem to remember.","TWN":"除此之外……我什麼都不記得了。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그건 걱정 마시길. 제가 당신에 대해서 잘 알고 있으니까요.","JPN":"それは心配無用です。あなたのことは、よく知っていますから。","ENG":"Don't worry. I already know plenty about you.","TWN":"不用擔心，我對妳很瞭解。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Pardon?","TWN":"什麼……？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"방금 그 말, 정말인가요?","JPN":"今のお言葉、本当ですか？","ENG":"D-do you mean that?","TWN":"妳說的是真的？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네. 단언해 드리는데, 당신에 대해선 세상에서 두 번째로 잘 알고 있을 거예요.","JPN":"はい。断言しますが、あなたのことはこの世で2番目に詳しいでしょう。","ENG":"Yes. I can confidently say that there's only one other person who knows you better than I.","TWN":"是的，我敢說我是世界上最瞭解妳的人之一，至少能排在第二位。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는, 비록 기억을 잃었지만 소중한 무언가를 지켜야 한다는 의식만큼은 남아 있었어요.","JPN":"たとえ記憶を失ったとしても、私には大切な何かを守らなければならないという意識だけは残っていました。","ENG":"Although I've lost my memory, I seem to remember this feeling of having to protect something precious.","TWN":"我雖然失去了記憶，但卻記得要守護一個重要的東西。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 기억 속의 저는 그럴 만한 사람이 아닌 것 같더군요.","JPN":"しかし、記憶の中の私はそこまで優しい人物ではなかったようです。","ENG":"But the faint glimpse of whom I used to be tells me I wasn't exactly a protector of any kind.","TWN":"但記憶中的我好像沒有資格守護什麼東西。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그러니 알고 계시다면 대답해 주세요.","JPN":"だからご存知でしたら教えてください。","ENG":"So please tell me if you know the answer...","TWN":"所以，如果妳知道，請妳告訴我。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"손에 피를 묻히고 다니던 자가...... 대체 뭘 그렇게 지키고 싶어했는지.","JPN":"血に染まった手で……いったい何を守ろうとしていたのか。","ENG":"What was it that I wished to protect so dearly... with my bloodied hands?","TWN":"雙手沾滿鮮血的我……想守護的東西到底是什麼呢。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"너무 간단한 질문이네요. 당신 목숨이겠죠.","JPN":"簡単すぎる質問ですね。あなたの命でしょう。","ENG":"That's easy. Your life, probably.","TWN":"這個問題很簡單，當然是妳的性命了。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터의 명령을 거역한 메이드장 주제에, 혼자 살자고 악착같이 도망쳤던 배신자니까요.","JPN":"マスターの命令に逆らったメイド長のくせに、一人で生き延びようと逃げた裏切り者ですから。","ENG":"After all, you're nothing but a traitor who ran off to survive by yourself after you disobeyed the Master.","TWN":"妳不過就是個違抗主人命令的女僕長罷了，為了獨自活命而拼命逃走的叛徒。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......배신자?","JPN":"……裏切り者？","ENG":"A traitor?","TWN":"……叛徒？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스!","JPN":"リコリス！","ENG":"Lycoris!","TWN":"莉克麗絲！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"쳇, 내가 네 애완견이야?","JPN":"チェッ、私はあんたのお使いじゃないからね！","ENG":"Hmpf! Stop treating me like I'm your dog or something!","TWN":"切，妳當作在叫狗嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"거기 누구야! 순순히 기어 나와!","JPN":"そこにいるのは誰？　大人しく出てきて！","ENG":"Who's there! Show yourself!","TWN":"是誰！乖乖地給我滾出來！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으엑...... 차, 창으로 컨테이너를 날려 버렸슴다......?!","JPN":"ひえぇ……や、槍でコンテナを吹き飛ばしたんっすか？","ENG":"Eeep... Y-you blew away the container with your spear?","TWN":"額……居然用長矛打飛了集裝箱……？！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"잠깐, 쟨 또 누구야? 맨션 소속은 아닌 것 같은데?","JPN":"ちょっと待って、あの子は誰？　マンション所属に見えないけど。","ENG":"Huh? Who the heck is that? She doesn't seem like she's from the Mansion.","TWN":"等等，她又是誰？不像是曼森的人啊？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모네?! 회사에 있지 않고 여긴 왜 따라 온 거예요!","JPN":"モネ！？　会社にいる時間のはずなのに、ここで何をしているのですか？","ENG":"Mone! What are you doing here? You're supposed to be back at the office!","TWN":"莫妮？！妳不待在公司，跟來這裡做什麼！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"제, 제성함다......! 메이드장님이랑 주인님이 하던 얘기를 듣고 걱정돼서......!","JPN":"ご、ごめんなさいっす……！　メイド長とご主人様の話を聞いたら心配で……！","ENG":"I-I'm sorry, ma'am! But I got worried when I heard you speak with the Master...","TWN":"對、對不起……！我聽到您和主人的對話，很擔心您，所以才……！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"새로운 견습까지 들인 걸로도 모자라 다른 주인까지?","JPN":"新しい見習いまで作って、他のご主人様だと？","ENG":"You've taken on a new apprentice AND a new master too?","TWN":"妳不僅收了新的見習，居然還找了新主人？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그동안 아주 새 살림을 차렸군요.","JPN":"とんでもないことをしてくれましたね。","ENG":"You sure seem to have moved on with your life.","TWN":"看來妳這期間過得挺不錯啊。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"뻔뻔스러워. 불결해. 이 추잡한 배신자.","JPN":"図々しい。不潔極まりない。この軽薄な裏切り者。","ENG":"You shameless, unfaithful, wretched traitor.","TWN":"無恥之徒，骯髒的叛徒。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"새 주인도 당신 민낯을 알면 구역질이 날 걸.","JPN":"その新しい主もあなたの真の顔を知れば、吐き気がするでしょう。","ENG":"I'm sure your new master would be disgusted by your true colors.","TWN":"新主人如果知道妳的真面目，肯定也會覺得無比噁心。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터께 사죄할 기회라도 주려고 했지만, 계획이 달라졌어.","JPN":"マスターに謝罪する機会を与えるつもりだったけど、計画を変更する。","ENG":"I was going to give you a chance to atone for your treason against our Master, but I've changed my mind.","TWN":"本想給妳一個機會，讓妳跟頭目請罪，現在我看沒必要了。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"당장 폐기시켜 버리겠어! 이 배신자!","JPN":"今すぐこの場で廃棄してやる！　この裏切り者め！","ENG":"I'm going to put you down right now, traitor!","TWN":"我要馬上殺了妳！妳這個叛徒！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};